#include <bits/stdc++.h>
using namespace std;
const int  maxn=1e6+5;
int son[maxn][65];
int cnt[maxn],idx;
int get_id(char c) {
	return c-'a';
}
void insert(string &s) {
	int p=0;
	for(char c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			son[p][u]=++idx;
		}
		p=son[p][u];
	}
	cnt[p]++;
}
int query(string &s) {
	int p=0;
	for(char c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			return 0;
		}
		p=son[p][u];
	}
	return cnt[p];
}
void clear() {
	for(int i=0; i<=idx; i++) {
		for(int j=0; j<65; j++) {
			son[i][j]=0;
		}
		cnt[i]=0;
	}
	idx=0;
}
void slove(int q) {
	set<string> x;
	for(int i=1; i<=q; i++) {
		string s;
		cin>>s;
		int u=x.size();
		x.insert(s);
		if(x.size()==u) {
			cout<<"REPEAT";
		} else {
			if(query(s)) {
				cout<<"OK";
			} else {
				cout<<"WRONG";
				x.erase(s);
			}
		}
		cout<<"\n";
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n;
	cin>>n;
	for(int i=1; i<=n; i++) {
		string s;
		cin>>s;
		insert(s);
	}
	int q;
	cin>>q;
	slove(q);
	return 0;
}
